setup.command:
python3 - <<'PY'
from pathlib import Path
p = Path('x-pack/filebeat/input/httpjson/bug_precision_repro_test.go')
p.write_text('''package httpjson

import (
    "io"
    "net/http"
    "strings"
    "testing"
)

func TestGetIdsFromResponses_LargeIntegerPrecision(t *testing.T) {
    r := &requester{}
    resp := &http.Response{Body: io.NopCloser(strings.NewReader(`[9007199254740993]`))}

    ids, err := r.getIdsFromResponses([]*http.Response{resp}, "$[:]")
    if err != nil {
        t.Fatalf("unexpected error: %v", err)
    }
    if len(ids) != 1 {
        t.Fatalf("expected exactly one id, got %d (%v)", len(ids), ids)
    }

    want := "9007199254740993"
    if ids[0] != want {
        t.Fatalf("expected id %q, got %q", want, ids[0])
    }
}
''')
PY

patches.command:
python3 - <<'PY'
from pathlib import Path
p = Path('x-pack/filebeat/input/httpjson/request.go')
s = p.read_text()
old_decoder = '''		var v interface{}
		if err := json.Unmarshal(b, &v); err != nil {
			return nil, fmt.Errorf("cannot unmarshal data: %w", textContextError{error: err, body: b})
		}
'''
new_decoder = '''		var v interface{}
		dec := json.NewDecoder(bytes.NewReader(b))
		dec.UseNumber()
		if err := dec.Decode(&v); err != nil {
			return nil, fmt.Errorf("cannot unmarshal data: %w", textContextError{error: err, body: b})
		}
'''
old_switch = '''		case []interface{}:
			for _, v := range tresp {
				switch v.(type) {
				case float64, string:
					ids = append(ids, fmt.Sprintf("%v", v))
				default:
					r.log.Errorf("events must a number or string, but got %T: skipping", v)
					continue
				}
			}
		case float64, string:
			ids = append(ids, fmt.Sprintf("%v", tresp))
'''
new_switch = '''		case []interface{}:
			for _, v := range tresp {
				switch v.(type) {
				case float64, string, json.Number:
					ids = append(ids, fmt.Sprintf("%v", v))
				default:
					r.log.Errorf("events must a number or string, but got %T: skipping", v)
					continue
				}
			}
		case float64, string, json.Number:
			ids = append(ids, fmt.Sprintf("%v", tresp))
'''
if old_decoder not in s:
    raise SystemExit('decoder target text not found')
if old_switch not in s:
    raise SystemExit('switch target text not found')
s = s.replace(old_decoder, new_decoder).replace(old_switch, new_switch)
p.write_text(s)
PY
